#!/usr/bin/env node
/**
 * copy-unlock-catalog.mjs
 *
 * Copies the canonical unlock_catalog.json (generated by
 * tools/python-bridge/tools/srtlab_unlock_catalog_gen.py) into
 * artifacts/srt-lab/public/ so the SRT Lab frontend can fetch it as a
 * static asset at /unlock_catalog.json.
 *
 * Run automatically as part of `pnpm --filter @workspace/srt-lab dev` and
 * `... build` via the predev / prebuild hooks. Also runnable manually:
 *   node scripts/copy-unlock-catalog.mjs            # copy
 *   node scripts/copy-unlock-catalog.mjs --check    # CI: verify in sync
 */
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const REPO = resolve(ROOT, "..", "..");
const SRC = resolve(REPO, "tools/python-bridge/tools/unlock_catalog.json");
const DST = resolve(ROOT, "public/unlock_catalog.json");
// Task #634 — hand-curated extension entries are merged in after the
// canonical copy. Keeps the python-bridge source untouched (per project
// preference) while still surfacing the new XC2268 / Mopar radio /
// dealer-lockout / ZF-8HP capabilities in the canonical
// public/unlock_catalog.json that the frontend fetches.
const TASK634 = resolve(ROOT, "public/task634_entries.json");

const CHECK = process.argv.includes("--check");

if (!existsSync(SRC)) {
  console.error(
    `copy-unlock-catalog: source missing at ${SRC}. ` +
      `Generate it with: python3 tools/python-bridge/tools/srtlab_unlock_catalog_gen.py`,
  );
  process.exit(1);
}

function buildMerged() {
  const base = JSON.parse(readFileSync(SRC, "utf8"));
  if (existsSync(TASK634)) {
    const ext = JSON.parse(readFileSync(TASK634, "utf8"));
    if (ext && Array.isArray(ext.entries) && ext.entries.length) {
      base.task634_entries = ext.entries;
      base.task634_provenance = ext.provenance || "task-634";
    }
  }
  return JSON.stringify(base, null, 2) + "\n";
}

const src = buildMerged();
const dst = existsSync(DST) ? readFileSync(DST, "utf8") : "";

if (CHECK) {
  if (src !== dst) {
    console.error(
      "copy-unlock-catalog: public/unlock_catalog.json is out of date — " +
        "run `node scripts/copy-unlock-catalog.mjs`.",
    );
    process.exit(1);
  }
  console.log("copy-unlock-catalog: in sync.");
  process.exit(0);
}

if (src === dst) {
  console.log("copy-unlock-catalog: already in sync, nothing to do.");
  process.exit(0);
}

writeFileSync(DST, src);
console.log(`copy-unlock-catalog: wrote ${DST}`);
